function getGeminiText(nodeName) {
  try {
    const nodeData = $(nodeName).first().json;

    // Tenta múltiplos caminhos possíveis
    if (nodeData?.candidates?.[0]?.content?.parts?.[0]?.text) {
      return nodeData.candidates[0].content.parts[0].text;
    }
    if (nodeData?.text) return nodeData.text;
    if (nodeData?.output) return nodeData.output;
    if (nodeData?.body) return nodeData.body;
    if (typeof nodeData === 'string') return nodeData;

    return `[Aviso] Resposta de ${nodeName} indisponível.`;
  } catch (e) {
    return `[Erro em ${nodeName}] ${e.message}`;
  }
}

function getSafeOutput(nodeName) {
  try {
    const data = $(nodeName).first().json;
    return data?.output || data?.text || data?.body || JSON.stringify(data);
  } catch (e) {
    return `[Erro] ${nodeName}: ${e.message}`;
  }
}

const context = $('Build Context1').first().json.context;
const runTimestamp = $('Build Context1').first().json.runTimestamp;

const cfoReport = getSafeOutput('CFO Agent Buffett1');
const ctoReport = getSafeOutput('CTO Agent Torvalds1');
const cooReport = getGeminiText('COO Ohno1');
const cmoReport = getGeminiText('CMO Ogilvy1');
const cpoReport = getGeminiText('CPO Cagan1');

const compiledReport = [
  '=== RELATORIO CFO — Warren Buffett ===', cfoReport, '',
  '=== RELATORIO CTO — Linus Torvalds ===', ctoReport, '',
  '=== RELATORIO COO — Taiichi Ohno ===', cooReport, '',
  '=== RELATORIO CMO — David Ogilvy ===', cmoReport, '',
  '=== RELATORIO CPO — Marty Cagan ===', cpoReport
].join('\n');

if (!compiledReport || compiledReport.trim().length === 0) {
  throw new Error('Relatório compilado vazio! Verifique os agentes.');
}

return [{ 
  json: { 
    compiledReport, 
    context, 
    runTimestamp, 
    cfoReport, 
    ctoReport, 
    cooReport, 
    cmoReport, 
    cpoReport,
    reportGenerated: true
  } 
}];

function extractGeminiText(nodeName) {
  try {
    const r = $(nodeName).first().json;
    return r.candidates[0].content.parts[0].text;
  } catch(e) {
    return null;
  }
}

const ceoRaw = $json.candidates?.[0]?.content?.parts?.[0]?.text || "";
const runTimestamp = $('Build Context1').first().json.runTimestamp;
const compiledReport = $('Compile C-Level Reports1').first().json.compiledReport;

// Remove markdown code block se existir (```json ... ``` ou ``` ... ```)
let jsonStr = ceoRaw.trim();
const jsonMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/);
if (jsonMatch) jsonStr = jsonMatch[1].trim();

let ceoDecision = {};
try {
  ceoDecision = JSON.parse(jsonStr || '{}');
} catch(e) {
  ceoDecision = {
    resumo_executivo: ceoRaw || 'Análise automática do C-Suite concluída.',
    decisoes: [],
    titulo_issue_github: 'C-Suite Review — ' + runTimestamp.substring(0, 10),
    descricao_issue_github: '## Revisão Automática do C-Suite\n\n' + (ceoRaw || 'Sem detalhes disponíveis.'),
    mensagem_google_chat: 'C-Suite concluiu análise autónoma. Verifique o GitHub para detalhes.'
  };
}

// Normalizar chaves em inglês para português
if (!ceoDecision.resumo_executivo && ceoDecision.executive_summary) ceoDecision.resumo_executivo = ceoDecision.executive_summary;
if ((!ceoDecision.decisoes || !ceoDecision.decisoes.length) && ceoDecision.decisions?.length) ceoDecision.decisoes = ceoDecision.decisions;
if (!ceoDecision.titulo_issue_github && ceoDecision.issue_title) ceoDecision.titulo_issue_github = ceoDecision.issue_title;
if (!ceoDecision.descricao_issue_github && ceoDecision.issue_description) ceoDecision.descricao_issue_github = ceoDecision.issue_description;
if (!ceoDecision.mensagem_google_chat && ceoDecision.chat_message) ceoDecision.mensagem_google_chat = ceoDecision.chat_message;

// Validação crítica
if (!ceoDecision.descricao_issue_github || ceoDecision.descricao_issue_github.trim().length === 0) {
  throw new Error('CEODecision vazia! Verifique a resposta do CEO Grove.');
}

const issueTitle = (ceoDecision.titulo_issue_github || ('C-Suite Review — ' + runTimestamp.substring(0, 10))).substring(0, 256);

const issueBody = ceoDecision.descricao_issue_github ||
  '## Resumo Executivo\n\n' + (ceoDecision.resumo_executivo || 'Sem resumo.') +
  '\n\n## Decisões\n\n' + (JSON.stringify(ceoDecision.decisoes || [], null, 2)) +
  '\n\n---\n*Gerado automaticamente pelo C-Suite Loop — Adventure Labs OS*\n*Run: ' + runTimestamp + '*';

const chatMessage = ceoDecision.mensagem_google_chat || 'C-Suite Loop concluído. Verifique o GitHub.';
const summaryText = ceoDecision.resumo_executivo || issueTitle;

return [{ json: {
  ...ceoDecision,
  issueTitle,
  issueBody,
  chatMessage,
  summaryText,
  runTimestamp,
  compiledReport,
  readyForGitHub: true
} }];

